Here's a **simple file management system in Python** that allows users to **view, create, and delete files**, with **basic access control** based on user roles (e.g., `admin` or `user`). This system uses a simple text-based interface and stores user roles in a dictionary for demonstration purposes.

---

## ✅ Features:
- View all files in a directory
- Create a new file
- Delete a file
- Access control based on user role

---

## 📁 File Structure:
- `main.py` – Main script
- `files/` – Directory to store files (you can change this path)

---

## 📜 `main.py`

```python
import os
import sys

# Define the directory where files will be stored
FILE_DIR = "files/"

# User access levels
USER_ROLES = {
    "admin": ["view", "create", "delete"],
    "user": ["view", "create"]
}

def ensure_directory_exists():
    if not os.path.exists(FILE_DIR):
        os.makedirs(FILE_DIR)

def list_files():
    files = [f for f in os.listdir(FILE_DIR) if os.path.isfile(os.path.join(FILE_DIR, f))]
    if not files:
        print("No files found.")
    else:
        print("Files in directory:")
        for idx, file in enumerate(files, 1):
            print(f"{idx}. {file}")

def create_file():
    filename = input("Enter the filename to create: ")
    filepath = os.path.join(FILE_DIR, filename)
    if os.path.exists(filepath):
        print("File already exists.")
        return
    try:
        open(filepath, 'w').close()
        print(f"File '{filename}' created.")
    except Exception as e:
        print(f"Error creating file: {e}")

def delete_file():
    list_files()
    try:
        choice = int(input("Enter the number of the file to delete: "))
        files = [f for f in os.listdir(FILE_DIR) if os.path.isfile(os.path.join(FILE_DIR, f))]
        if 1 <= choice <= len(files):
            filename = files[choice - 1]
            filepath = os.path.join(FILE_DIR, filename)
            os.remove(filepath)
            print(f"File '{filename}' deleted.")
        else:
            print("Invalid choice.")
    except (ValueError, IndexError):
        print("Invalid input. Please enter a valid number.")

def main():
    ensure_directory_exists()
    print("Welcome to the File Management System")
    print("Available commands: view, create, delete, exit")

    user_role = input("Enter your role (admin/user): ").lower()
    if user_role not in USER_ROLES:
        print("Invalid role. Exiting.")
        return

    while True:
        command = input("Enter command (view/create/delete/exit): ").lower()
        if command == "view":
            if "view" in USER_ROLES[user_role]:
                list_files()
            else:
                print("You don't have permission to view files.")
        elif command == "create":
            if "create" in USER_ROLES[user_role]:
                create_file()
            else:
                print("You don't have permission to create files.")
        elif command == "delete":
            if "delete" in USER_ROLES[user_role]:
                delete_file()
            else:
                print("You don't have permission to delete files.")
        elif command == "exit":
            print("Exiting the system.")
            break
        else:
            print("Invalid command. Try again.")

if __name__ == "__main__":
    main()
```

