## ✅ Example: Implementing Server-Side Encryption with AWS CDK

### 1. **Install AWS CDK**

If you haven't already, install the AWS CDK CLI and the necessary libraries:

```bash
npm install -g aws-cdk
npm install @aws-cdk/aws-s3 @aws-cdk/aws-kms
```

---

### 2. **Implementing SSE-S3 (SSE with S3-Managed Keys)**

```typescript
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as s3 from 'aws-cdk-lib/aws-s3';

export class SseS3BucketStack extends cdk.Stack {
  constructor(scope: Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // Create an S3 bucket with server-side encryption using S3-managed keys
    const encryptedBucket = new s3.Bucket(this, 'EncryptedBucket', {
      encryption: s3.BucketEncryption.S3_MANAGED, // SSE-S3
    });

    // Optional: Add a policy or other configurations
    encryptedBucket.addToResourcePolicy(
      new s3.PolicyStatement({
        actions: ['s3:GetObject', 's3:PutObject'],
        principals: [new s3.ArnPrincipal('arn:aws:iam::123456789012:user/MyUser')],
        resources: [encryptedBucket.arnForObjects('*')],
      })
    );
  }
}
```

---

### 3. **Implementing SSE-KMS (SSE with KMS Key)**

If you want to use a **customer-managed KMS key**, you can do the following:

```typescript
import * as cdk from 'aws-cdk-lib';
import { Construct } from 'constructs';
import * as s3 from 'aws-cdk-lib/aws-s3';
import * as kms from 'aws-cdk-lib/aws-kms';

export class SseKmsBucketStack extends cdk.Stack {
  constructor(scope: Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // Create a KMS key
    const encryptionKey = new kms.Key(this, 'EncryptionKey', {
      description: 'KMS key for S3 encryption',
      enableKeyRotation: true,
    });

    // Create an S3 bucket with server-side encryption using KMS
    const encryptedBucket = new s3.Bucket(this, 'EncryptedBucket', {
      encryption: s3.BucketEncryption.KMS,
      encryptionKey, // Use the KMS key
    });

    // Optional: Add a policy or other configurations
    encryptedBucket.addToResourcePolicy(
      new s3.PolicyStatement({
        actions: ['s3:GetObject', 's3:PutObject'],
        principals: [new s3.ArnPrincipal('arn:aws:iam::123456789012:user/MyUser')],
        resources: [encryptedBucket.arnForObjects('*')],
      })
    );
  }
}
```

