Creating a simple web application that allows users to **register** and **view their profile information** can be done using **HTML**, **CSS**, and **JavaScript** for the front end, and **Node.js** with **Express** and **MongoDB** for the back end. Here's a step-by-step guide to help you build this:

---

## 🧱 1. Set Up Your Project Structure

Create a folder for your project:

```
my-web-app/
├── public/
│   ├── index.html
│   ├── profile.html
│   └── styles.css
├── server/
│   ├── app.js
│   └── models/
│       └── User.js
├── package.json
└── .gitignore
```

---

## 📦 2. Install Dependencies

In the root of your project, run:

```bash
npm init -y
npm install express mongoose body-parser
```

---

## 📄 3. Set Up the Server (server/app.js)

```javascript
const express = require('express');
const mongoose = require('mongoose');
const bodyParser = require('body-parser');
const User = require('./models/User');

const app = express();
const PORT = 3000;

// Connect to MongoDB
mongoose.connect('mongodb://localhost:27017/userDB', {
  useNewUrlParser: true,
  useUnifiedTopology: true
});

// Middleware
app.use(bodyParser.urlencoded({ extended: true }));
app.use(express.static('public'));

// Routes
app.get('/', (req, res) => {
  res.redirect('/register');
});

app.get('/register', (req, res) => {
  res.sendFile(__dirname + '/public/index.html');
});

app.post('/register', async (req, res) => {
  const { username, email, password } = req.body;
  try {
    const user = new User({ username, email, password });
    await user.save();
    res.redirect('/profile');
  } catch (err) {
    res.status(500).send('Error registering user');
  }
});

app.get('/profile', async (req, res) => {
  try {
    const user = await User.findOne({ username: req.query.username });
    if (!user) return res.status(404).send('User not found');
    res.sendFile(__dirname + '/public/profile.html');
  } catch (err) {
    res.status(500).send('Error fetching profile');
  }
});

app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});
```

---

## 🧱 4. Create the User Model (server/models/User.js)

```javascript
const mongoose = require('mongoose');

const userSchema = new mongoose.Schema({
  username: { type: String, required: true, unique: true },
  email: { type: String, required: true, unique: true },
  password: { type: String, required: true }
});

module.exports = mongoose.model('User', userSchema);
```

